function escapeHtml(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function formatEmailHtml(text) {
  // Split on the intentional double-newline (greeting vs. body)
  const paragraphs = text
    .split(/\n\s*\n/)
    .map(p => p.replace(/\s+/g, ' ').trim()) // clean up accidental wraps within each paragraph
    .filter(Boolean);
  return paragraphs.map(p => `<p>${escapeHtml(p)}</p>`).join('');
}

const raw = $input.first().json.output;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    email_message: `Hi {{name}},\n\nWe missed you at the viewing today — would you like to reschedule? Just reply to this email.`,
    whatsapp_message: `Hi! Sorry we missed each other today — want to reschedule?`
  };
}

const leadData = $('Extract Lead Details').first().json;
const emailHtml = formatEmailHtml(
  parsed.email_message.includes('\n\n')
    ? parsed.email_message
    : parsed.email_message.replace(leadData.leadName, `${leadData.leadName},\n\n`) // fallback if AI forgets the break
);
const cleanWhatsapp = parsed.whatsapp_message.replace(/\s+/g, ' ').trim();

return [{
  json: {
    ...leadData,
    email_message: emailHtml,
    whatsapp_message: cleanWhatsapp,
    recordId: `${leadData.leadEmail}-${Date.now()}`
  }
}];
